{"code":"// Create the email body with all incident IDs
const incidentIds = highUrgencyTriggered.map(incident => incident.id).join('\n');

// Send the email
email.send_email({
  to: 'oncall@acme.io',
  subject: 'Triage',
  body: incidentIds
});

// Return the action taken and count
`Sent email to oncall@acme.io with ${highUrgencyTriggered.length} incident IDs: ${incidentIds}`"}
